import numpy as np

def estimate_dla_dimension(generators, tol=1e-8):
    dim = generators[0].shape[0]

    def is_independent(basis, new):
        if not basis:
            return np.linalg.norm(new) > tol
        flat = [b.flatten() for b in basis]
        new_flat = new.flatten()
        A = np.column_stack(flat + [new_flat])
        return np.linalg.matrix_rank(A, tol) > np.linalg.matrix_rank(A[:, :-1], tol)

    def commutator(A, B):
        return A @ B - B @ A

    basis = []
    for g in generators:
        g_traceless = g - np.trace(g)/dim * np.eye(dim)
        if is_independent(basis, g_traceless):
            basis.append(g_traceless)

    for _ in range(50):
        new_elements = []
        for i, A in enumerate(basis):
            for j, B in enumerate(basis):
                if i < j:
                    comm = commutator(A, B)
                    if np.linalg.norm(comm) > tol:
                        if is_independent(basis + new_elements, comm):
                            new_elements.append(comm)

        if not new_elements:
            break
        basis.extend(new_elements)

    return len(basis)

def pauli_generator(n_qubits, pauli, qubit):
    paulis = {
        'X': np.array([[0, 1], [1, 0]]),
        'Y': np.array([[0, -1j], [1j, 0]]),
        'Z': np.array([[1, 0], [0, -1]])
    }

    result = np.eye(1)
    for q in range(n_qubits):
        if q == qubit:
            result = np.kron(result, paulis[pauli])
        else:
            result = np.kron(result, np.eye(2))

    return -1j * result / 2

n_qubits = 2
gens = [pauli_generator(n_qubits, p, q) 
        for p in ['X', 'Y', 'Z'] for q in range(n_qubits)]

dim = estimate_dla_dimension(gens)
print(f"DLA dimension for {n_qubits} qubits, single-qubit gates: {dim}")
print(f"(Expected: 3n = {3*n_qubits} for product unitaries)")

import numpy as np

def verify_concentration(n_qubits, observable_type='local', n_samples=1000):
    dim = 2 ** n_qubits

    def sample_haar_state():
        real = np.random.randn(dim)
        imag = np.random.randn(dim)
        state = real + 1j * imag
        return state / np.linalg.norm(state)

    values = []
    for _ in range(n_samples):
        state = sample_haar_state()

        if observable_type == 'local':
            # <Z_0>
            exp = 0
            for z in range(dim):
                prob = np.abs(state[z])**2
                bit = (z >> (n_qubits - 1)) & 1
                exp += prob * (1 - 2 * bit)
        else:
            # <Z^⊗n>
            exp = 0
            for z in range(dim):
                prob = np.abs(state[z])**2
                parity = bin(z).count('1') % 2
                exp += prob * (1 - 2 * parity)

        values.append(exp)

    values = np.array(values)

    # Theoretical: for Haar states, std ~ 1/sqrt(d) for local
    if observable_type == 'local':
        theory_std = 1 / np.sqrt(dim)
    else:
        theory_std = 1 / np.sqrt(dim)

    return {
        'mean': np.mean(values),
        'std': np.std(values),
        'theory_std': theory_std
    }

print("Concentration Verification")
print("=" * 50)

for n in [2, 4, 6, 8]:
    for obs in ['local', 'global']:
        result = verify_concentration(n, obs)
        print(f"n={n}, {obs}: std={result['std']:.4f}, theory={result['theory_std']:.4f}")

import numpy as np

class TrainabilityPredictor:
    def __init__(self):
        pass

    def predict(self, n_qubits, n_layers, cost_locality, init_type):
        # Depth score: good if L <= 2*log2(n)
        log_threshold = 2 * np.log2(n_qubits)
        if n_layers <= log_threshold:
            depth_score = 1.0
        elif n_layers <= n_qubits:
            depth_score = 0.5
        else:
            depth_score = 0.1

        # Locality score: good if k <= 2
        if cost_locality <= 2:
            locality_score = 1.0
        elif cost_locality <= n_qubits // 2:
            locality_score = 0.5
        else:
            locality_score = 0.1

        # Init score
        init_score = 1.0 if init_type == 'identity' else 0.3

        # Combined score
        score = depth_score * locality_score * init_score

        if score > 0.5:
            prediction = 'Trainable'
        elif score > 0.2:
            prediction = 'Marginal'
        else:
            prediction = 'Difficult'

        return {
            'prediction': prediction,
            'score': score,
            'depth_score': depth_score,
            'locality_score': locality_score,
            'init_score': init_score
        }

    def validate(self, n_qubits, n_layers, cost_locality, init_type, n_samples=50):
        dim = 2 ** n_qubits
        n_params = n_qubits * n_layers

        def circuit(params):
            state = np.zeros(dim, dtype=complex)
            state[0] = 1
            idx = 0
            for _ in range(n_layers):
                for q in range(n_qubits):
                    theta = params[idx]
                    c, s = np.cos(theta/2), np.sin(theta/2)
                    new = np.zeros_like(state)
                    for z in range(dim):
                        zf = z ^ (1 << (n_qubits-1-q))
                        new[z] = c*state[z] - s*state[zf]
                        new[zf] = s*state[z] + c*state[zf]
                    state = new
                    idx += 1
            return state

        def cost(params):
            state = circuit(params)
            c = 0
            for z in range(dim):
                prob = np.abs(state[z])**2
                relevant = z >> (n_qubits - cost_locality)
                parity = bin(relevant).count('1') % 2
                c += prob * (1 - 2 * parity)
            return c

        grads = []
        for _ in range(n_samples):
            if init_type == 'identity':
                params = np.random.uniform(-0.1, 0.1, n_params)
            else:
                params = np.random.uniform(0, 2*np.pi, n_params)
            pp, pm = params.copy(), params.copy()
            pp[0] += np.pi/2
            pm[0] -= np.pi/2
            grads.append((cost(pp) - cost(pm))/2)

        return np.var(grads)

predictor = TrainabilityPredictor()

cases = [
    (4, 2, 1, 'identity'),
    (4, 8, 4, 'random'),
    (8, 3, 2, 'identity'),
    (8, 16, 8, 'random'),
]

print("Trainability Predictions")
print("=" * 70)

for n, L, k, init in cases:
    result = predictor.predict(n, L, k, init)
    print(f"n={n}, L={L}, {k}-local, {init}: {result['prediction']} (score={result['score']:.2f})")
